        require(close_fee > 0 && close_fee <= MAX_CLOSE_FEE);
        require(tx.outputs.length == 1);
        require(tx.outputs[0].scriptPubKey == byte[](new ScriptPubKeyP2PK(pubkey(creator_pubkey))));
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value - close_fee);
    }

    // Anyone may add carrier without changing ticket ownership, counters, the
    // draw commitment, or the refund deadline. The funding input authorizes
    // its own KAS; the covenant only accepts the exact declared increase.
    entrypoint function topUp(int top_up_amount) {
        require(top_up_amount > 0);
        require(max_tickets > 0 && max_tickets <= 1000000 && min_tickets > 0 && min_tickets <= max_tickets);
        require(max_batches > 0 && max_batches <= MAX_ROUND_BATCHES && ticket_price >= MIN_REFUNDABLE_TICKET_PRICE && ticket_price <= MAX_ROUND_PRINCIPAL / max_tickets);
        require(sold_tickets >= 0 && sold_tickets <= max_tickets);
        require(sold_batches >= 0 && sold_batches <= max_batches && sold_batches <= sold_tickets);
        if (sold_tickets == 0) { require(sold_batches == 0); }
        else { require(sold_batches > 0); }
        require(rootFromFrontier(sold_batches) == ticket_root);
        // Once the minimum is met, this covenant's DAA is part of the draw
        // boundary. A later top-up would let a funder move that boundary.
        // The input-DAA check also bounds an after-deadline top-up race to one.
        require(sold_tickets < min_tickets && OpTxInputDaaScore(this.activeInputIndex) < sales_deadline_daa);
        require(refund_cursor == 0 && refund_batch_cursor == 0);
        require(OpAuthOutputCount(this.activeInputIndex) == 1);
        int cov_out_idx = OpAuthOutputIdx(this.activeInputIndex, 0);
        require(tx.outputs[cov_out_idx].value == tx.inputs[this.activeInputIndex].value + top_up_amount);
        validateOutputState(cov_out_idx, {
            round_nonce: round_nonce, max_tickets: max_tickets, min_tickets: min_tickets, max_batches: max_batches,
            ticket_price: ticket_price, creator_pubkey: creator_pubkey, sales_deadline_daa: sales_deadline_daa,
            sold_tickets: sold_tickets, sold_batches: sold_batches, ticket_root: ticket_root,
            frontier: frontier, refund_cursor: refund_cursor, refund_batch_cursor: refund_batch_cursor,
        });
    }
}
